        align-items: center;
        gap: 10px;
        font-size: 16px;
        font-weight: 700;
        color: #e9e3ff;
        letter-spacing: 0.3px;
        text-shadow: 0 1px 2px rgba(0,0,0,0.35);
        position: relative;
      }

      .moon-svg {
        width: 22px;
        height: 22px;
        display: block;
      }

      .toggle-icon {
        width: 28px;
        height: 28px;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        flex-shrink: 0;
        /* 静态星形，无动画 */
        clip-path: polygon(50% 0%, 61.8% 38.2%, 100% 50%, 61.8% 61.8%, 50% 100%, 38.2% 61.8%, 0% 50%, 38.2% 38.2%);
        background:
          radial-gradient(circle at center, rgba(255,255,255,0.15) 0%, transparent 70%),
          linear-gradient(135deg, rgba(141,121,222,0.6), rgba(109,97,184,0.4));
